mapper.select:
SELECT tdio.TIME as time, tdio.CPU_RATE as cpuRate, tdio.MEMORY_RATE as memoryRate, tdio.HUGEPAGE_MEM_RATE as hugepageMemRate, tdio.VM_GROUP_MEM_RATE as vmGroupMemRate, tdio.OVS_GROUP_MEM_RATE as ovsGroupMemRate, tdio.HOST_ID as hostId, TT.name as hostName FROM  TBL_HOST_CPU_MEM_DETAIL
tdio INNER JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST} TT ON tdio.HOST_ID=TT.id
WHERE tdio.TIME BETWEEN ${startTime} AND ${endTime}

    AND tdio.HOST_ID in (${hostIds})


    AND tdio.OP_GROUP_CODE LIKE #{operatorGroupCode}

ORDER BY tdio.TIME ASC

SELECT  detail.HOST_ID,


        SUM(detail.CPU_RATE) as cpuRate,


        SUM(detail.MEMORY_RATE) as memoryRate,


MIN(TIME) as time FROM TBL_HOST_CPU_MEM_DETAIL detail INNER JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST}
host ON host.id = detail.HOST_ID WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND detail.OP_GROUP_CODE LIKE #{operatorGroupCode}


    AND detail.HOST_POOL_ID =${hostPoolId}


    AND detail.CLUSTER_ID =${clusterId}


    AND detail.HOST_ID in (${hostIds})

GROUP BY detail.HOST_ID


        ORDER BY cpuRate DESC


        ORDER BY memoryRate DESC




    LIMIT ${limit}

SELECT  detail.HOST_ID,


        ROUND(AVG(detail.CPU_RATE),2) as cpuRate


        ROUND(AVG(detail.MEMORY_RATE),2) as memoryRate


FROM TBL_HOST_CPU_MEM_DETAIL detail INNER JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST}
host ON host.id = detail.HOST_ID
WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND detail.OP_GROUP_CODE LIKE #{operatorGroupCode}


    AND detail.HOST_POOL_ID =${hostPoolId}


    AND detail.CLUSTER_ID =${clusterId}


    AND detail.HOST_ID in (${hostIds})


    AND detail.CLUSTER_ID in (${clusterIds})

GROUP BY detail.HOST_ID


        ORDER BY cpuRate DESC


        ORDER BY memoryRate DESC




    LIMIT ${limit}

SELECT ROUND(avg(CPU_RATE),2) as cpuRate,ROUND(avg(MEMORY_RATE),2) as memoryRate,HOST_ID as hostId  FROM TBL_HOST_CPU_MEM_DETAIL  WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND OP_GROUP_CODE LIKE #{operatorGroupCode}


    AND HOST_POOL_ID =${hostPoolId}


    AND CLUSTER_ID =${clusterId}


    AND HOST_ID in (${hostIds})


    AND HOST_ID =${hostId}

GROUP BY HOST_ID

SELECT MAX(CPU_RATE) as cpuRate,MAX(MEMORY_RATE) as memoryRate,HOST_ID as hostId  FROM TBL_HOST_CPU_MEM_DETAIL  WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND OP_GROUP_CODE LIKE #{operatorGroupCode}


    AND HOST_POOL_ID =${hostPoolId}


    AND CLUSTER_ID =${clusterId}

GROUP BY HOST_ID

SELECT HOST_ID as hostId FROM TBL_HOST_CPU_MEM_DETAIL B INNER JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST}
host ON host.id = B.HOST_ID WHERE host.maintain = 0 AND host.status = 1

    AND B.CLUSTER_ID =${clusterId}

AND (

    B.CPU_RATE ${cpuComparison} ${cpuThreshold}


    ${conditionRelation}


    B.MEMORY_RATE ${memComparison} ${memThreshold}


    ${conditionRelation}


    B.FLOW_STAT ${flowComparison} ${flowThreshold}

) AND TIME BETWEEN ${startTime} AND ${endTime}  GROUP BY HOST_ID HAVING

    MIN(B.CPU_RATE) ${cpuComparison} ${cpuThreshold}


    MAX(B.CPU_RATE) ${cpuComparison} ${cpuThreshold}


    ${conditionRelation}


     MIN(B.MEMORY_RATE) ${memComparison} ${memThreshold}


    MAX(B.MEMORY_RATE) ${memComparison} ${memThreshold}


    ${conditionRelation}


    MIN(B.FLOW_STAT) ${flowComparison} ${flowThreshold}


    MAX(B.FLOW_STAT) ${flowComparison} ${flowThreshold}

SELECT ROUND(AVG(CPU_RATE),2) as cpuRate, ROUND(AVG(MEMORY_RATE),2) as memoryRate, CLUSTER_ID as clusterId FROM TBL_HOST_CPU_MEM_DETAIL WHERE TIME = (SELECT MAX(TIME)-${duration} FROM TBL_HOST_CPU_MEM_DETAIL)
AND CLUSTER_ID=${clusterId}
group by CLUSTER_ID

SELECT TIME as time, CPU_RATE as cpuRate, CPU_USAGE_MHZ as cpuUsage, MEMORY_RATE as memoryRate, HOST_ID as hostId, HOST_POOL_ID as hostpoolId,
CLUSTER_ID as clusterId, OP_GROUP_CODE as operatorGroupCode, OP_GROUP_ID as operatorGroupId, FLOW_STAT as  flowStat, BUFFER_RATE as bufferRate,
HUGEPAGE_MEM_RATE as hugepageMemRate,VM_GROUP_MEM_RATE as vmGroupMemRate,OVS_GROUP_MEM_RATE as ovsGroupMemRate,
CACHED_RATE as cachedRate, SWAP_RATE as swapRate FROM TBL_HOST_CPU_MEM_DETAIL C
WHERE C.TIME=( SELECT MAX(TIME) FROM TBL_HOST_CPU_MEM_DETAIL)-${duration}

    AND C.OP_GROUP_CODE LIKE #{operatorGroupCode}


    AND C.HOST_POOL_ID =${hostPoolId}


    AND C.CLUSTER_ID =${clusterId}


    AND C.HOST_ID =${hostId}


    AND HOST_ID in (${hostIds})

SELECT ROUND(AVG(CPU_RATE),2) as cpuRate,ROUND(AVG(MEMORY_RATE),2) as memoryRate FROM TBL_HOST_CPU_MEM_DETAIL  WHERE HOST_ID = ${hostId}
AND TIME >= (SELECT MAX(TIME) FROM TBL_HOST_CPU_MEM_DETAIL  WHERE HOST_ID = ${hostId}) -${duration}
GROUP BY HOST_ID
